-- Case 026: transaction block, query history, RESULT_SCAN, and session variables
SET TARGET_TABLE = 'MART.TENANT_DAILY_METRIC'; SET RUN_ID = UUID_STRING(); BEGIN; CREATE OR REPLACE TEMPORARY TABLE QA.RUN_QUERY_PROFILE AS SELECT query_id,user_name,role_name,warehouse_name,start_time,end_time,execution_status,total_elapsed_time,rows_produced,bytes_scanned,query_text FROM TABLE(INFORMATION_SCHEMA.QUERY_HISTORY(END_TIME_RANGE_START => DATEADD( 'hour',-2,CURRENT_TIMESTAMP()),END_TIME_RANGE_END => CURRENT_TIMESTAMP(),RESULT_LIMIT => 10000)) WHERE query_text ILIKE '%' || $TARGET_TABLE || '%' AND execution_status IN( 'SUCCESS', 'FAILED_WITH_ERROR'); INSERT INTO OPS.QUERY_AUDIT_SUMMARY(run_id,target_table,status,query_count,failed_count,total_elapsed_ms,created_at) SELECT $RUN_ID,$TARGET_TABLE,IFF(COUNT_IF(execution_status <> 'SUCCESS') > 0, 'HAS_FAILURE', 'OK'),COUNT(*),COUNT_IF(execution_status <> 'SUCCESS'),SUM(total_elapsed_time),CURRENT_TIMESTAMP() FROM QA.RUN_QUERY_PROFILE; SELECT * FROM IDENTIFIER($TARGET_TABLE) WHERE metric_date = CURRENT_DATE() LIMIT 10; CREATE OR REPLACE TEMPORARY TABLE QA.TARGET_TABLE_SAMPLE AS SELECT *,CURRENT_TIMESTAMP() AS sampled_at,LAST_QUERY_ID() AS source_query_id FROM TABLE(RESULT_SCAN(LAST_QUERY_ID())); COMMIT;
